import java.io.*;
import java.util.*;

public class Main {
    private static int findMin(int[] nums) {
        int left = 0, right = nums.length - 1;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] > nums[right]) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return nums[left];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append(' ');
        }
        // Replace escaped newline sequences with spaces to handle inputs like "1\\n5\\n..."
        String cleaned = raw.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(cleaned);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int n = Integer.parseInt(st.nextToken());
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = Integer.parseInt(st.nextToken());
            }
            sb.append(findMin(arr)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

